// Load questions into subjects
export function loadAllQuestions() {
  const phy1 = subjects.find(s => s.id === 'phy1');
  if (phy1 && phy1.questions.length === 0) phy1.questions = phy1Questions;

  const phy12 = subjects.find(s => s.id === '12th_phy');
  if (phy12 && phy12.questions.length === 0) phy12.questions = phy12Questions;

  // BEE and Mechanics use pre-existing questions from quizData
  // For chem, bee, mech, pre_bee, pre_mech we populate with questions from root files
  const bee = subjects.find(s => s.id === 'bee');
  if (bee && bee.questions.length === 0) bee.questions = beeQuestions;
  const preBee = subjects.find(s => s.id === 'pre_bee');
  if (preBee && preBee.questions.length === 0) preBee.questions = preBeeQuestions;
  const mech = subjects.find(s => s.id === 'mech');
  if (mech && mech.questions.length === 0) mech.questions = mechQuestions;
  const preMech = subjects.find(s => s.id === 'pre_mech');
  if (preMech && preMech.questions.length === 0) preMech.questions = preMechQuestions;
  const chem = subjects.find(s => s.id === 'chem1');
  if (chem && chem.questions.length === 0) chem.questions = chemQuestions;
}

